long long compute_lcp(const string& a, const string& b) {
    long long min_len = min(a.length(), b.length());
    for (long long i = 0; i < min_len; ++i) {
        if (a[i] != b[i]) {
            return i;
        }
    }
    return min_len;
}

vector<long long> solve(vector<string> words) {
    int n = words.size();
    if (n == 0) return {};
    if (n == 1) return {0};
    vector<long long> lcp(n - 1, 0);
    for (int i = 0; i < n - 1; ++i) {
        lcp[i] = compute_lcp(words[i], words[i + 1]);
    }

    vector<long long> prefix_max(n - 1, 0);
    prefix_max[0] = lcp[0];
    for (int i = 1; i < n - 1; ++i) {
        prefix_max[i] = max(prefix_max[i - 1], lcp[i]);
    }

    vector<long long> suffix_max(n - 1, 0);
    suffix_max[n - 2] = lcp[n - 2];
    for (int i = n - 3; i >= 0; --i) {
        suffix_max[i] = max(suffix_max[i + 1], lcp[i]);
    }

